import { Product } from "../lib/types/Product";
import { v4 as uuid } from "uuid";

const STORAGE_KEY = "inventary2_products";

const getData = (): Product[] => {
  const raw = localStorage.getItem(STORAGE_KEY);
  return raw ? JSON.parse(raw) : [];
};

const persist = (products: Product[]) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(products));
};

export const productService = {
  async list(): Promise<Product[]> {
    // simulamos latencia
    return new Promise((res) => setTimeout(() => res(getData()), 500));
  },
  async create(data: Omit<Product, "id" | "createdAt" | "updatedAt">) {
    const products = getData();
    const newProduct: Product = {
      ...data,
      id: uuid(),
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };
    products.push(newProduct);
    persist(products);
    return newProduct;
  },
  async update(id: string, changes: Partial<Product>) {
    let products = getData();
    products = products.map((p) =>
      p.id === id ? { ...p, ...changes, updatedAt: new Date().toISOString() } : p
    );
    persist(products);
    return products.find((p) => p.id === id)!;
  },
};

