export const reportService = {
  async monthly(month: number, year: number) {
    const dummy: Sale[] = [];
    // Simulación con datos aleatorios
    for (let i = 1; i <= 10; i++) {
      dummy.push({
        id: `${year}-${month}-${i}`,
        productId: `prod-${i}`,
        quantity: Math.floor(Math.random() * 20),
        total: Math.random() * 100,
        date: new Date(year, month, i).toISOString(),
      });
    }
    const total = dummy.reduce((acc, s) => acc + s.total, 0);
    return {
      sales: dummy,
      totalFormatted: formatCurrency(total),
    };
  },
};

import { StockAlert } from "../lib/types/Alert";
import { v4 as uuid } from "uuid";

const alerts: StockAlert[] = [];

export const alertService = {
  async list() {
    return alerts;
  },
  async create(productId: string, message: string) {
    const alert: StockAlert = {
      id: uuid(),
      productId,
      message,
      createdAt: new Date().toISOString(),
      read: false,
    };
    alerts.push(alert);
    return alert;
  },
  async markRead(id: string) {
    const alert = alerts.find((a) => a.id === id);
    if (alert) alert.read = true;
    return alert;
  },
};

import React, { createContext, useContext, useEffect, useState } from "react";
import { Product } from "../lib/types/Product";
import { productService } from "../services/productService";

interface ProductContextProps {
  products: Product[];
  loading: boolean;
  addProduct: (p: Omit<Product, "id" | "createdAt" | "updatedAt">) => Promise<void>;
  updateProduct: (id: string, changes: Partial<Product>) => Promise<void>;
}

const ProductContext = createContext<ProductContextProps | undefined>(undefined);

export const ProductProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    productService.list().then((data) => {
      setProducts(data);
      setLoading(false);
    });
  }, []);

  const addProduct: ProductContextProps["addProduct"] = async (p) => {
    const newP = await productService.create(p);
    setProducts((prev) => [...prev, newP]);
  };

  const updateProduct: ProductContextProps["updateProduct"] = async (id, c) => {
    const updated = await productService.update(id, c);
    setProducts((prev) => prev.map((p) => (p.id === id ? updated : p)));
  };

  return (
    <ProductContext.Provider value={{ products, loading, addProduct, updateProduct }}>
      {children}
    </ProductContext.Provider>
  );
};

export const useProductContext = () => {
  const ctx = useContext(ProductContext);
  if (!ctx) throw new Error("useProductContext must be used within ProductProvider");
  return ctx;
};

import React, { createContext, useContext, useEffect, useState } from "react";
import { StockAlert } from "../lib/types/Alert";
import { alertService } from "../services/alertService";

interface AlertCtx {
  alerts: StockAlert[];
  refresh: () => void;
  markRead: (id: string) => void;
}

const AlertContext = createContext<AlertCtx | undefined>(undefined);

export const AlertProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [alerts, setAlerts] = useState<StockAlert[]>([]);

  const refresh = () => {
    alertService.list().then(setAlerts);
  };

  useEffect(refresh, []);

  const markRead = (id: string) => {
    alertService.markRead(id).then(() => refresh());
  };

  return (
    <AlertContext.Provider value={{ alerts, refresh, markRead }}>
      {children}
    </AlertContext.Provider>
  );
};

export const useAlertContext = () => {
  const ctx = useContext(AlertContext);
  if (!ctx) throw new Error("useAlertContext must be used within AlertProvider");
  return ctx;
};

import { useMemo } from "react";
import { useProducts } from "./useProducts";
import { formatCurrency } from "../lib/utils/formatCurrency";

export const useDashboardMetrics = () => {
  const { products } = useProducts();

  return useMemo(() => {
    const totalProducts = products.length;
    const inventoryValue = products.reduce((acc, p) => acc + p.price * p.stock, 0);
    const lowStock = products.filter((p) => p.stock <= p.minStock).length;

    return {
      totalProducts,
      inventoryValueFormatted: formatCurrency(inventoryValue),
      lowStock,
    };
  }, [products]);
};

