export const ProductForm: React.FC<Props> = ({ initial, onSubmit }) => {
  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm<Omit<Product, "id" | "createdAt" | "updatedAt">>({
    defaultValues: {
      name: "",
      sku: "",
      price: 0,
      stock: 0,
      minStock: 0,
      category: "General",
    },
  });

  useEffect(() => {
    if (initial) reset(initial);
  }, [initial, reset]);

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
      <div>
        <label className="block mb-1 text-sm font-medium">Nombre</label>
        <Input {...register("name", { required: true })} />
        {errors.name && <span className="text-red-500 text-sm">Requerido</span>}
      </div>

      <div>
        <label className="block mb-1 text-sm font-medium">SKU</label>
        <Input {...register("sku", { required: true })} />
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block mb-1 text-sm font-medium">Precio</label>
          <Input type="number" step="0.01" {...register("price", { required: true, min: 0 })} />
        </div>
        <div>
          <label className="block mb-1 text-sm font-medium">Stock Inicial</label>
          <Input type="number" {...register("stock", { required: true, min: 0 })} />
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block mb-1 text-sm font-medium">Stock Mínimo Alerta</label>
          <Input type="number" {...register("minStock", { required: true, min: 0 })} />
        </div>
        <div>
          <label className="block mb-1 text-sm font-medium">Categoría</label>
          <Select {...register("category")}> 
            <option value="General">General</option>
            <option value="Bebidas">Bebidas</option>
            <option value="Alimentos">Alimentos</option>
          </Select>
        </div>
      </div>

      <Button type="submit">Guardar</Button>
    </form>
  );
};

