import React, { useState } from "react";
import { useProducts } from "../hooks/useProducts";
import { Card } from "../components/ui/Card";
import { Button } from "../components/ui/Button";
import { ProductForm } from "../components/shared/ProductForm";
import { calcStockStatus } from "../lib/utils/calcStock";

export const Products: React.FC = () => {
  const { products, addProduct } = useProducts();
  const [showForm, setShowForm] = useState(false);

  return (
    <div className="space-y-6">
      <header className="flex justify-between items-center">
        <h1 className="text-2xl font-bold">Productos</h1>
        <Button onClick={() => setShowForm((s) => !s)}>
          {showForm ? "Cerrar" : "Agregar Producto"}
        </Button>
      </header>

      {showForm && (
        <Card>
          <ProductForm
            onSubmit={async (data) => {
              await addProduct(data);
              setShowForm(false);
            }}
          />
        </Card>
      )}

      <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {products.map((p) => {
          const status = calcStockStatus(p);
          const statusColor =
            status === "low" ? "text-yellow-600" : status === "out" ? "text-red-600" : "text-green-600";
          return (
            <Card key={p.id} className="space-y-2">
              <h3 className="font-semibold text-lg flex justify-between">
                {p.name} <span className={statusColor}>{p.stock}</span>
              </h3>
              <p className="text-sm text-gray-500">SKU: {p.sku}</p>
              <p className="text-sm text-gray-500">Precio: ${p.price.toFixed(2)}</p>
            </Card>
          );
        })}
      </section>
    </div>
  );
};

import React, { useState } from "react";
import { reportService } from "../services/reportService";
import { formatCurrency } from "../lib/utils/formatCurrency";
import { Card } from "../components/ui/Card";
import { Button } from "../components/ui/Button";

export const Reports: React.FC = () => {
  const [month, setMonth] = useState<number>(new Date().getMonth());
  const [year, setYear] = useState<number>(new Date().getFullYear());
  const [data, setData] = useState<{ totalFormatted: string } | null>(null);
  const [loading, setLoading] = useState(false);

  const generate = async () => {
    setLoading(true);
    const res = await reportService.monthly(month, year);
    setData(res);
    setLoading(false);
  };

  return (
    <div className="space-y-6 max-w-md">
      <h1 className="text-2xl font-bold">Reportes Mensuales</h1>

      <div className="flex gap-2">
        <select
          value={month}
          onChange={(e) => setMonth(Number(e.target.value))}
          className="border rounded px-2 py-1"
        >
          {Array.from({ length: 12 }).map((_, idx) => (
            <option key={idx} value={idx}>
              {new Date(0, idx).toLocaleString("es-ES", { month: "long" })}
            </option>
          ))}
        </select>
        <input
          type="number"
          value={year}
          onChange={(e) => setYear(Number(e.target.value))}
          className="border rounded px-2 py-1 w-24"
        />
        <Button onClick={generate} disabled={loading}>
          {loading ? "Generando..." : "Generar"}
        </Button>
      </div>

      {data && (
        <Card>
          <h2 className="text-lg font-semibold mb-2">Resumen</h2>
          <p>Total ventas: {data.totalFormatted}</p>
        </Card>
      )}
    </div>
  );
};

